import type { InvalidateQueryFilters, QueryClient, QueryKey } from '@tanstack/react-query';
import { Shot, GenerationRow } from '@/domains/generation/types';
import { queryKeys } from '@/shared/lib/queryKeys';

function getShotsProjectPrefix(projectId: string): readonly QueryKey {
  return [...queryKeys.shots.all, projectId] as const;
}

function getShotListQueries(queryClient: QueryClient, projectId: string) {
  return queryClient.getQueriesData<Shot[]>({
    queryKey: getShotsProjectPrefix(projectId),
  });
}

/**
 * @param onlyExisting - If true, only update caches that already exist.
 *                       If false (default), will create cache entries if needed.
 */
export function updateAllShotsCaches(
  queryClient: QueryClient,
  projectId: string,
  updater: (old: Shot[] | undefined) => Shot[],
  onlyExisting: boolean = false
): void {
  const cachedQueries = getShotListQueries(queryClient, projectId);
  if (cachedQueries.length === 0) {
    if (!onlyExisting) {
      queryClient.setQueryData<Shot[]>(
        queryKeys.shots.list(projectId, 0),
        (old) => updater(old)
      );
    }
    return;
  }

  cachedQueries.forEach(([key, existing]) => {
    if (onlyExisting && existing === undefined) {
      return;
    }
    queryClient.setQueryData<Shot[]>(key, (old) => updater(old));
  });
}

export function rollbackShotsCaches(
  queryClient: QueryClient,
  projectId: string,
  previous: Shot[] | undefined
): void {
  if (!previous) return;
  const cachedQueries = getShotListQueries(queryClient, projectId);
  if (cachedQueries.length === 0) {
    queryClient.setQueryData(queryKeys.shots.list(projectId, 0), previous);
    return;
  }

  cachedQueries.forEach(([key]) => {
    queryClient.setQueryData(key, previous);
  });
}

export async function cancelShotsQueries(
  queryClient: QueryClient,
  projectId: string
): Promise<void> {
  await queryClient.cancelQueries({ queryKey: getShotsProjectPrefix(projectId) });
}

export function invalidateShotsQueries(
  queryClient: QueryClient,
  projectId: string,
  filters: Omit<InvalidateQueryFilters, 'queryKey'> = {},
): void {
  queryClient.invalidateQueries({
    queryKey: [...queryKeys.shots.all, projectId],
    ...filters,
  });
}

export function findShotsCache(
  queryClient: QueryClient,
  projectId: string
): Shot[] | undefined {
  const cachedQueries = getShotListQueries(queryClient, projectId);
  for (const [, data] of cachedQueries) {
    if (data && data.length > 0) {
      return data;
    }
  }
  for (const [, data] of cachedQueries) {
    if (data !== undefined) {
      return data;
    }
  }
  return undefined;
}

export function upsertShotInCache(
  queryClient: QueryClient,
  projectId: string,
  shot: Shot
): void {
  const shotPosition = shot.position ?? Number.MAX_SAFE_INTEGER;

  updateAllShotsCaches(queryClient, projectId, (oldShots = []) => {
    const remainingShots = oldShots.filter((existingShot) => existingShot.id !== shot.id);
    const insertionIndex = remainingShots.findIndex(
      (existingShot) => (existingShot.position ?? Number.MAX_SAFE_INTEGER) > shotPosition
    );

    if (insertionIndex === -1) {
      return [...remainingShots, shot];
    }

    const updatedShots = [...remainingShots];
    updatedShots.splice(insertionIndex, 0, shot);
    return updatedShots;
  });

  queryClient.setQueryData(queryKeys.shots.detail(shot.id), shot);
}

export function rollbackShotGenerationsCache(
  queryClient: QueryClient,
  shotId: string,
  previous: GenerationRow[] | undefined
): void {
  if (!previous) return;
  queryClient.setQueryData(queryKeys.generations.byShot(shotId), previous);
}

export async function cancelShotGenerationsQuery(
  queryClient: QueryClient,
  shotId: string
): Promise<void> {
  await queryClient.cancelQueries({ queryKey: queryKeys.generations.byShot(shotId) });
}

import React, { createContext, useContext, ReactNode, useMemo, useState, useEffect } from 'react';
import { useListShots, useProjectImageStats } from '@/shared/hooks/shots';
import { useProject } from '@/shared/contexts/ProjectContext';
import { Shot } from '@/domains/generation/types';

interface ShotsContextType {
  shots: Shot[] | undefined;
  isLoading: boolean;
  error: Error | null;
  refetchShots: () => void;
  // Stats for SHOT_FILTER.ALL and SHOT_FILTER.NO_SHOT filters
  allImagesCount?: number;
  noShotImagesCount?: number;
}

const ShotsContext = createContext<ShotsContextType | undefined>(undefined);

interface ShotsProviderProps {
  children: ReactNode;
}

export const ShotsProvider: React.FC<ShotsProviderProps> = ({ children }) => {
  const { selectedProjectId } = useProject();

  const [isProjectTransitioning, setIsProjectTransitioning] = useState(false);
  const prevProjectIdRef = React.useRef<string | null>(null);

  // Load all images per shot (0 = unlimited)
  // Previously limited to 2 on mobile for performance, but this broke expand/collapse UI
  const maxImagesPerShot = 0;

  const { data: shots, isLoading: isShotsLoading, isFetching: isShotsFetching, error: shotsError, refetch } = useListShots(selectedProjectId, { maxImagesPerShot });

  // Load project-wide image stats
  const { data: projectStats, isLoading: isStatsLoading } = useProjectImageStats(selectedProjectId);

  // Set transitioning flag when project changes
  useEffect(() => {
    if (prevProjectIdRef.current !== null && prevProjectIdRef.current !== selectedProjectId) {
      setIsProjectTransitioning(true);
    }
    prevProjectIdRef.current = selectedProjectId;
  }, [selectedProjectId]);

  // Clear transitioning flag when new data arrives
  useEffect(() => {
    if (isProjectTransitioning && !isShotsFetching && shots !== undefined) {
      setIsProjectTransitioning(false);
    }
  }, [isProjectTransitioning, isShotsFetching, shots]);

  // Show loading during transition or actual loading
  const isLoading = isShotsLoading || isStatsLoading || isProjectTransitioning;
  const error = shotsError;

  // Return undefined for shots during transition to force skeleton display
  // This prevents showing stale data from a previously cached project
  const effectiveShots = isProjectTransitioning ? undefined : shots;

  // Memoize context value to prevent unnecessary re-renders of consumers
  const value = useMemo<ShotsContextType>(() => ({
    shots: effectiveShots,
    isLoading,
    error,
    refetchShots: refetch,
    allImagesCount: projectStats?.allCount,
    noShotImagesCount: projectStats?.noShotCount,
  }), [effectiveShots, isLoading, error, refetch, projectStats]);

  return (
    <ShotsContext.Provider value={value}>
      {children}
    </ShotsContext.Provider>
  );
};

export const useShots = (): ShotsContextType => {
  const context = useContext(ShotsContext);
  if (context === undefined) {
    throw new Error('useShots must be used within a ShotsProvider');
  }
  return context;
};

import { describe, expect, it } from 'vitest';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { ResolvedTimelineClip, TrackDefinition } from '@/tools/video-editor/types';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import { resolveSelectedGenerationIdsForShotCreation, resolveWaveformAudioSrc } from './TimelineEditor';

describe('resolveSelectedGenerationIdsForShotCreation', () => {
  const rows: TimelineRow[] = [
    {
      id: 'V1',
      actions: [
        { id: 'clip-2', start: 5, end: 8, effectId: 'effect-2' },
        { id: 'clip-1', start: 1, end: 4, effectId: 'effect-1' },
      ],
    },
    {
      id: 'V2',
      actions: [
        { id: 'clip-3', start: 0, end: 2, effectId: 'effect-3' },
      ],
    },
  ];

  const meta: Record<string, ClipMeta> = {
    'clip-1': { asset: 'asset-1', track: 'V1', clipType: 'media' },
    'clip-2': { asset: 'asset-2', track: 'V1', clipType: 'media' },
    'clip-3': { asset: 'asset-3', track: 'V2', clipType: 'media' },
  };

  it('sorts selected generation ids by track index and clip start', () => {
    const assetGenerationMap = {
      'asset-1': 'gen-1',
      'asset-2': 'gen-2',
      'asset-3': 'gen-3',
    };

    const result = resolveSelectedGenerationIdsForShotCreation({
      rows,
      meta,
      assetGenerationMap,
      selectedClipIds: ['clip-3', 'clip-1', 'clip-2'],
    });

    expect(result).toEqual({
      canCreateShot: true,
      generationIds: ['gen-1', 'gen-2', 'gen-3'],
    });
  });

  it('marks the selection as ineligible when any selected clip lacks a generation id', () => {
    const assetGenerationMap = {
      'asset-1': 'gen-1',
      'asset-3': 'gen-3',
    };

    const result = resolveSelectedGenerationIdsForShotCreation({
      rows,
      meta,
      assetGenerationMap,
      selectedClipIds: ['clip-1', 'clip-2', 'clip-3'],
    });

    expect(result.canCreateShot).toBe(false);
    expect(result.generationIds).toEqual(['gen-1', 'gen-3']);
  });
});

describe('resolveWaveformAudioSrc', () => {
  const audioTrack: TrackDefinition = { id: 'A1', kind: 'audio', label: 'A1' };
  const visualTrack: TrackDefinition = { id: 'V1', kind: 'visual', label: 'V1' };

  const createClip = (overrides: Partial<ResolvedTimelineClip> = {}): ResolvedTimelineClip => ({
    id: 'clip-1',
    at: 0,
    track: 'V1',
    clipType: 'media',
    volume: 1,
    asset: 'asset-1',
    assetEntry: {
      file: 'asset.mp4',
      src: 'https://example.com/asset.mp4',
      type: 'video/mp4',
    },
    ...overrides,
  });

  it('returns audio src for audible audio-track clips', () => {
    expect(resolveWaveformAudioSrc(createClip({ track: 'A1' }), audioTrack)).toBe('https://example.com/asset.mp4');
  });

  it('returns audio src for audible visual-track video clips', () => {
    expect(resolveWaveformAudioSrc(createClip(), visualTrack)).toBe('https://example.com/asset.mp4');
  });

  it('returns undefined for muted visual clips so detach-audio moves the waveform to the new audio clip', () => {
    const mutedVisualClip = createClip({ volume: 0 });
    const detachedAudioClip = createClip({ id: 'clip-1-audio', track: 'A1', volume: 1 });

    expect(resolveWaveformAudioSrc(mutedVisualClip, visualTrack)).toBeUndefined();
    expect(resolveWaveformAudioSrc(detachedAudioClip, audioTrack)).toBe('https://example.com/asset.mp4');
  });

  it('returns undefined for non-video visual clips and text/effect clips', () => {
    expect(resolveWaveformAudioSrc(createClip({
      assetEntry: {
        file: 'asset.png',
        src: 'https://example.com/asset.png',
        type: 'image/png',
      },
    }), visualTrack)).toBeUndefined();
    expect(resolveWaveformAudioSrc(createClip({ clipType: 'text' }), visualTrack)).toBeUndefined();
    expect(resolveWaveformAudioSrc(createClip({ clipType: 'effect-layer' }), visualTrack)).toBeUndefined();
  });
});

