export async function createShotWithGenerationsPath(
  input: CreateShotWithGenerationsPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    generationIds,
    queryClient,
    createShotWithGenerations,
  } = input;

  const rpcResult = await createShotWithGenerations({
    projectId: selectedProjectId,
    shotName,
    generationIds,
  });

  if (!rpcResult?.shot_id) {
    throw new Error('Shot creation failed - no ID returned');
  }

  const images = rpcResult.shot_generations.map(mapRpcShotGenerationToRow);
  const stats = buildShotStats(images);
  const shot: Shot = {
    id: rpcResult.shot_id,
    name: rpcResult.shot_name,
    project_id: selectedProjectId,
    position: rpcResult.shot_position,
    images,
    ...stats,
  };

  upsertShotInCache(queryClient, selectedProjectId, shot);

  enqueueGenerationsInvalidation(queryClient, rpcResult.shot_id, {
    reason: 'create-shot-with-generations',
    scope: 'all',
    includeShots: false,
    projectId: selectedProjectId,
    includeProjectUnified: true,
  });

  invalidateShotsQueries(queryClient, selectedProjectId);

  return {
    shotId: rpcResult.shot_id,
    shotName: rpcResult.shot_name || shotName,
    shot,
    generationIds,
  };
}

import { useCallback, useState } from 'react';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import {
  useShotFinalVideos,
  type ShotFinalVideo,
} from '@/tools/travel-between-images/hooks/video/useShotFinalVideos';

export type { ShotFinalVideo };

export const dismissedFinalVideoIds = new Set<string>();

export function useFinalVideoAvailable() {
  const { selectedProjectId } = useProjectSelectionContext();
  const { finalVideoMap } = useShotFinalVideos(selectedProjectId);
  const [, forceRender] = useState(0);

  const dismissFinalVideo = useCallback((finalVideoId: string) => {
    dismissedFinalVideoIds.add(finalVideoId);
    forceRender((count) => count + 1);
  }, []);

  return {
    finalVideoMap,
    dismissedFinalVideoIds,
    dismissFinalVideo,
  };
}

  return undefined;
}

export function resolveFinalVideoShotIds({
  rows,
  meta,
  registry,
  finalVideoMap,
  dismissedFinalVideoIds,
}: {
  rows: TimelineRow[];
  meta: Record<string, ClipMeta>;
  registry: AssetRegistry;
  finalVideoMap: Map<string, ShotFinalVideo>;
  dismissedFinalVideoIds: Set<string>;
}) {
  const timelineClipGenerationIds = new Set<string>();
  for (const row of rows) {
    for (const action of row.actions) {
      const assetKey = meta[action.id]?.asset;
      const generationId = assetKey ? registry.assets[assetKey]?.generationId : undefined;
      if (typeof generationId === 'string' && generationId.length > 0) {
        timelineClipGenerationIds.add(generationId);
      }
    }
  }

  const shotIds = new Set<string>();
  for (const [shotId, finalVideo] of finalVideoMap) {
    if (dismissedFinalVideoIds.has(finalVideo.id) || timelineClipGenerationIds.has(finalVideo.id)) {
      continue;
    }
    shotIds.add(shotId);
  }

  return shotIds;
}

